class Solution:
    def closeStrings(self, word1: str, word2: str) -> bool:
        from collections import Counter
        c1, c2 = Counter(word1), Counter(word2)
        if set(c1.keys()) != set(c2.keys()):
            return False
        freq1 = Counter(c1.values())
        freq2 = Counter(c2.values())
        return freq1 == freq2

