class Solution:
    def closeStrings(self, word1: str, word2: str) -> bool:
        from collections import Counter
        c1, c2 = Counter(word1), Counter(word2)
        if set(c1) != set(c2):
            return False
        return sorted(c1.values()) == sorted(c2.values())

